const widget = space.chat.transient.get("snake-game");
if (!widget) throw new Error("snake-game widget not found in transient");

const text = typeof widget === "string" ? widget : (widget.text?.() ?? widget.content ?? "");
const source = String(text);

const styleInsert = `
const CELL_SIZE = 20;
const MOVE_DURATION = 120; // ms
`;

const needsCellSize = !/CELL_SIZE\s*=/.test(source);
const needsDuration = !/MOVE_DURATION\s*=/.test(source);

let patched = source;

if (needsCellSize || needsDuration) {
  const anchor = /const\s+GRID_SIZE\s*=\s*\d+;[ \t]*\n/;
  if (anchor.test(patched)) {
    patched = patched.replace(anchor, match => match + (needsCellSize ? `const CELL_SIZE = 20;\n` : "") + (needsDuration ? `const MOVE_DURATION = 120; // ms\n` : ""));
  } else if (!needsCellSize || !needsDuration) {
    patched = styleInsert + "\n" + patched;
  }
}

patched = patched
  .replace(
    /(\bctx\.fillRect\(\s*x\s*,\s*y\s*,\s*GRID_SIZE\s*,\s*GRID_SIZE\s*\);)/g,
    `ctx.save();
ctx.translate(x, y);
ctx.fillRect(0, 0, GRID_SIZE, GRID_SIZE);
ctx.restore();`
  )
  .replace(
    /(\blet\s+lastMoveTime\s*=\s*0;)/,
    `$1
let animating = false;
let animFrom = null;
let animTo = null;
let animStart = 0;`
  )
  .replace(
    /(\bfunction\s+moveSnake\s*\([\s\S]*?\{\n)/,
    `$1  const now = performance.now();
`
  );

if (patched === source) {
  throw new Error("No patch was applied; source pattern not found.");
}

return await space.current.patchWidget("snake-game", {
  edits: [{ text: patched }]
});

