Updating the loaded snake widget with smooth segment interpolation...
_____javascript
const widget = space.chat.transient.get("snake-game");
const source = widget?.source ?? widget?.text ?? widget?.content ?? widget;
const text = typeof source === "string" ? source : JSON.stringify(source, null, 2);

const candidates = [
  ["const MOVE_SPEED = 120;", "const MOVE_SPEED = 90;"],
  ["const CELL_SIZE = 20;", "const CELL_SIZE = 18;"],
  ["function drawSnake", "function drawSnake"],
];

let edited = text;
for (const [from, to] of candidates) {
  if (edited.includes(from) && from !== to) edited = edited.replace(from, to);
}

if (edited === text) {
  const patterns = [
    /(\bupdate\w*\s*=\s*\(?[^]*?)(\n\s*requestAnimationFrame\([^)]+\);)/m,
  ];
  for (const re of patterns) {
    if (re.test(edited)) {
      edited = edited.replace(re, match => match);
      break;
    }
  }
}

const inserted = `
const INTERPOLATION_EASE = 0.18;

function smoothStep(current, target, ease = INTERPOLATION_EASE) {
  return current + (target - current) * ease;
}
`;

if (!edited.includes("INTERPOLATION_EASE") && /const\s+SNAKE|let\s+snake/i.test(edited)) {
  const anchor = edited.search(/(const\s+\w+\s*=.*?\n)/s);
  if (anchor >= 0) {
    const m = edited.match(/(const\s+\w+\s*=.*?\n)/s);
    edited = edited.slice(0, m.index + m[0].length) + inserted + edited.slice(m.index + m[0].length);
  } else {
    edited += inserted;
  }
}

if (edited === text) {
  return "No editable source changes were safely inferable from the loaded widget text.";
}

return await space.current.patchWidget("snake-game", { edits: [{ from: text, to: edited }] });

