const widget = space.chat.transient.get("snake-game");
const text = widget?.text ?? widget?.source ?? widget?.content ?? "";
const s = String(text);

const replacements = [
  [
    /(\bmove\b[\s\S]*?\{[\s\S]*?)(\/\/\s*step to next cell[\s\S]*?)(\n\s*\/\*[\s\S]*?\*\/)?/m,
    "$1// step to next cell with eased interpolation"
  ]
];

let out = s;

const easingInsert = (src) => {
  if (/easeInOut|lerp|transitionProgress|animationFrame/.test(src)) return src;

  let r = src;

  r = r.replace(
    /const\s+stepDuration\s*=\s*([^;\n]+);/,
    (m, v) =>
      `${m}\nconst animationDuration = ${v};\nconst easeInOut = (t) => t < 0.5 ? 2 * t * t : 1 - Math.pow(-2 * t + 2, 2) / 2;`
  );

  r = r.replace(
    /(\bfunction\s+moveSnake\b[\s\S]*?\{[\s\S]*?)(const\s+head\b[\s\S]*?\n)/,
    (m, pre, head) =>
      `${pre}const transitionProgress = Math.min(1, (performance.now() - lastMoveAt) / animationDuration);\nconst easedProgress = easeInOut(transitionProgress);\n${head}`
  );

  r = r.replace(
    /(\bconst\s+drawSnake\s*=\s*\([\s\S]*?\{[\s\S]*?)(ctx\.fillRect\([\s\S]*?\n)/,
    (m, pre, draw) =>
      `${pre}const renderX = cellX + dx * easedProgress;\nconst renderY = cellY + dy * easedProgress;\n${draw}`
  );

  r = r.replace(
    /ctx\.fillRect\(\s*cellX\s*,\s*cellY\s*,\s*cellSize\s*,\s*cellSize\s*\)/g,
    "ctx.fillRect(renderX, renderY, cellSize, cellSize)"
  );

  r = r.replace(
    /requestAnimationFrame\(([^)]+)\);/g,
    "requestAnimationFrame($1);"
  );

  return r;
};

out = easingInsert(out);

if (out === s) {
  throw new Error("No editable animation hook found in snake widget source.");
}

return await space.current.patchWidget("snake-game", {
  edits: [
    { from: s, to: out }
  ]
})

